const row = $input.item.json;
const isInstagram = (row.platform || '').toLowerCase() === 'instagram';
const imageType = row.image_type || (isInstagram ? 'text_card' : null);

if (!isInstagram) {
  return row;
}

if (imageType === 'photo') {
  return { ...row, _needsPhoto: true, _photoTheme: row.image_theme || '' };
}

const style = row.image_style || 'quote';
const body = row.body || '';
const sentences = body.match(/[^.!?]+[.!?]+/g) || [body.slice(0, 200)];

let apiBody;
if (style === 'editorial') {
  apiBody = {
    style: 'editorial',
    headline: (sentences[0] || '').trim().slice(0, 200),
    body: (sentences[1] || '').trim().slice(0, 300)
  };
} else {
  const quoteText = sentences.slice(0, 2).join(' ').trim().slice(0, 400);
  apiBody = { style: 'quote', text: quoteText };
}

return { ...row, _needsImage: true, _apiBody: apiBody };

const apiResp = $input.item.json;
const row = $('Image Router').item.json;
// Strip internal routing fields, set media_url from API response
const { _needsImage, _apiBody, ...cleanRow } = row;
cleanRow.media_url = (apiResp && apiResp.url) || null;
return cleanRow;

const library = $('Fetch Photo Library').item.json;
const row = $('Image Router').item.json;
const photos = library.photos || [];
const theme = row._photoTheme || '';
let filtered = photos.filter(p => p.theme && p.theme.toLowerCase().includes(theme.toLowerCase()));
if (filtered.length === 0) filtered = photos;
const selected = filtered[Math.floor(Math.random() * filtered.length)];
const { _needsPhoto, _photoTheme, ...cleanRow } = row;
cleanRow.media_url = selected ? selected.public_url : null;
return cleanRow;

